{
  "verses": [
    {
      "n": 16,
      "column": "left",
      "text": "Zik labbakt irr Gudribu\n3, dabbuht neka Seltn/ un Sapra-\nschann dabbuht malka wairak ne-\nka Sudrabs.\n"
    },
    {
      "n": 17,
      "column": "left",
      "text": "To Rahmo Zeltſch irr no\nLanna attkahpt/ kas fawu Zeltu\nfarga/ tas farga fawu Dweh-\nfelt.\n"
    },
    {
      "n": 18,
      "column": "left",
      "text": "Lepniba nahe preekich Je-\ndeldefchanas/ un preekſch Bohja-\nEfchanas nahe lepnis Prahts.\n"
    },
    {
      "n": 19,
      "column": "left",
      "text": "Labbaki irr pasemmigu\nPrahtu turreht ar teem Pasem-\nmigeen/ neka Laupijumu dal-\nliht ar Lepneem.\n"
    },
    {
      "n": 20,
      "column": "left",
      "text": "Kas lahdu Leetu prahtigi\npadarra/ tas atraddibs Labbu-\nmu/ un fwehtigs irr/ kas us to\nKUNGU pafaischahs.\n"
    },
    {
      "n": 21,
      "column": "left",
      "text": "Kam gudra Sirde irr/\ntas tobp par faprattigu nsteikts/\nun kas mihligi runna/ tas wai-\nrak ismahza.\n"
    },
    {
      "n": 22,
      "column": "left",
      "text": "Sapraschana irr dsihws\nAwots tam/ kam ta irr/ bet to\nGettu Pamahzischana irr Gef-\nkha.\n"
    },
    {
      "n": 23,
      "column": "left",
      "text": "Ta Sirde weena Gudra\ndarra winna Mutti faprattigu /\nun waire winna Luhpahm to\nMahzitchanu.\n"
    },
    {
      "n": 24,
      "column": "left",
      "text": "Lipniga Walloa irr tihrs\nMeddus/ tat Dwehfelei falda/\nun teem Kauleem weena Ahstes-\nSahte.\n"
    },
    {
      "n": 25,
      "column": "left",
      "text": "Dasch Zeltsch leekehs\npreekſch lahdu Wihrn taiſns ef-\n"
    },
    {
      "n": 26,
      "column": "right",
      "text": "* Kas (zittu) apbehdna/\ntas apbehdna few patchu / jo\ntahds atdarra fawu Mutti prett\nfew patchu.\n"
    },
    {
      "n": 27,
      "column": "right",
      "text": "Weens negohda Zilweks\nrohk pehz Nelaimi/ un us win-\nna Luhpahm irr ta ka deggohts\nUgguns.\n"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Weens pahrwehrtihts Zil-\nweks zelt Kildn/ un weens Ap-\nrunnatajs darra Schkelschanu\nstarp Leeleem-Kungeem.\n"
    },
    {
      "n": 29,
      "column": "right",
      "text": "Weens Warras-Darri-\ntajs wiſt tawn Tuwaku/ un us-\nwedd to us nelabhu Zeltu.\n"
    },
    {
      "n": 30,
      "column": "right",
      "text": "Kas ar fawami Azzim\nmirkschkina/ tas dohma pahr-\nwehrtitas Leetas / kas fawas\nLuhpas takohsch / tas padarra\nLannn.\n"
    },
    {
      "n": 31,
      "column": "right",
      "text": "Sirnee Matti irr weens\nGohda-Krohnis/ kas us to Zeltu\ntahs Taifnibas tohp atrasti.\n"
    },
    {
      "n": 32,
      "column": "right",
      "text": "Weens Lehuprahtigs irr\nlabbaks neka weens Stiprajs/\nun kas pahr fawu Prahtu wal-\nda/(irr labbaks)neka kas Pils-\nfahtu usjem.\n"
    },
    {
      "n": 33,
      "column": "right",
      "text": "Kaulint tobp mesti Kleh-\npi/ bet no ta KUNGA nahe\nwiſta winna Nolemischana.\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
